CREATE OR REPLACE FUNCTION quotes.ins_quote_head(json_data json)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_updated json;
    v_id integer;
BEGIN

    -- insert a new record into the quote table
    INSERT INTO quotes.quote (quote_number, customer_id, ragione_sociale, deal_number, owner, document_date,
                              document_type, replace_orders, template, services, proposal_type, initial_term_months,
                              next_term_months, bill_months, delivered_in_days, date_sent, status, notes,
                              nrc_charge_time,hs_deal_id, description, hs_quote_id, payment_method, trial)
    VALUES (json_data ->> 'quote_number', (json_data ->> 'customer_id')::bigint, json_data ->> 'ragione_sociale',
            json_data ->> 'deal_number', json_data ->> 'owner', (json_data ->> 'document_date')::date,
            json_data ->> 'document_type', json_data ->> 'replace_orders', json_data ->> 'template',
            json_data ->> 'services', json_data ->> 'proposal_type', (json_data ->> 'initial_term_months')::integer,
            (json_data ->> 'next_term_months')::integer, (json_data ->> 'bill_months')::integer,
            (json_data ->> 'delivered_in_days')::smallint, (json_data ->> 'date_sent')::date, json_data ->> 'status',
            json_data ->> 'notes', (json_data ->> 'nrc_charge_time')::integer, (json_data ->> 'hs_deal_id')::bigint,
            json_data ->> 'description', (json_data ->> 'hs_quote_id')::bigint, json_data ->> 'payment_method', json_data ->> 'trial')
    RETURNING id INTO v_id;

    -- Check if the insert was successful
    IF NOT FOUND THEN
        v_updated = json_build_object('id', -1,'status', 'ERROR', 'message', 'Insert failed')::json;
        RETURN v_updated;
    END IF;

    v_updated = json_build_object('id', v_id, 'status', 'OK', 'message', 'Update successful')::json;
    RETURN v_updated;
EXCEPTION
    WHEN OTHERS THEN
        -- Handle any other exceptions
        v_updated = json_build_object('id', -1, 'status', 'ERROR', 'message', SQLERRM)::json;
        RETURN v_updated;
END;
$function$

CREATE OR REPLACE FUNCTION quotes.upd_quote_row_product(json_data json)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
declare
    v_updated                    bool;
    v_id                         integer;
    v_quote_row_id               integer;
    v_group_name                 text;
begin


    v_id = (json_data ->> 'id')::integer;

    -- recupero quote_row_id
    select quote_row_id, group_name from quotes.quote_rows_products where id = v_id into v_quote_row_id, v_group_name;

    -- verifico che v_quote_row_id sia valorizzato
    if v_quote_row_id is null then
        raise exception 'quote_row_id non valorizzato';
    end if;

    -- se questa riga ha included = true rimuovo l'included precedente (va fatto per group name)
    update quotes.quote_rows_products set included = false
    where quote_row_id = v_quote_row_id and group_name = v_group_name and included = true;

    -- aggiorno il nuovo prodotto
    update quotes.quote_rows_products set
        included = json_data ->> 'included' = 'true',
        extended_description = json_data ->> 'extended_description',
        nrc = (json_data ->> 'nrc')::numeric,
        mrc = (json_data ->> 'mrc')::numeric,
        quantity = (json_data ->> 'quantity')::smallint
    where id = v_id;

    -- aggiorno i totali della riga (spostato in un trigger)
--     update quotes.quote_rows set
--         nrc_row = (select sum(nrc*quantity) from quotes.quote_rows_products where quote_row_id = v_quote_row_id),
--         mrc_row = (select sum(mrc*quantity) from quotes.quote_rows_products where quote_row_id = v_quote_row_id)
--     where id = v_quote_row_id;

    v_updated = true;
    return v_updated;
end;

$function$

CREATE OR REPLACE FUNCTION quotes.update_kit_product_rows()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_kit products.kit%ROWTYPE;
    v_lang character varying(2);
    v_main_product_internal_name character varying(255);
    v_main_product_translation_uuid uuid;
    v_legal_note text;
    v_extended_description text;
BEGIN
    select id, internal_name, main_product_code, initial_subscription_months, next_subscription_months, activation_time_days, nrc, mrc, translation_uuid, bundle_prefix, ecommerce, category_id, is_main_prd_sellable, is_active
    into v_kit
    from products.kit
    where id= NEW.kit_id;

    -- recupero la lingua della quote basandomi sul template
    select coalesce(template.lang,'it') from quotes.quote
    left join quotes.template on template.template_id = quote.template
    where quote.id = NEW.quote_id into v_lang;

    -- Elimina le righe esistenti in quote_rows_products per il kit_id modificato
    DELETE FROM quotes.quote_rows_products
    WHERE quote_row_id = OLD.id;


    -- se kit.is_main_product_sellable is true Inserisco una riga con il main product del kit
    IF v_kit.is_main_prd_sellable THEN
        select REPLACE(coalesce(common.get_long_translation(v_main_product_translation_uuid, v_lang),'') ||
                coalesce(common.get_long_translation(v_kit.translation_uuid, v_lang),''), E'\n', '<br>') into v_extended_description;
        if v_extended_description <> '' then
            v_extended_description := '<p>' || v_extended_description || '</p>';
        end if;
        select internal_name, translation_uuid
        from products.product
        where code = v_kit.main_product_code
        into v_main_product_internal_name, v_main_product_translation_uuid;
        INSERT INTO quotes.quote_rows_products (quote_row_id, product_code, minimum, maximum, required, nrc, mrc, position, group_name,main_product,included,quantity, extended_description)
        VALUES
            (NEW.id ,  v_kit.main_product_code,  1, -1, true, v_kit.nrc, v_kit.mrc, 0, v_main_product_internal_name ,true,true,1,
             v_extended_description)
        ;
    END IF;

    -- Inserisci le nuove righe da products.kit_product per il kit_id aggiornato
    INSERT INTO quotes.quote_rows_products (quote_row_id, product_code, minimum, maximum, required, nrc, mrc, position,
           group_name,quantity, extended_description)
    SELECT NEW.id as quote_row_id,  kp.product_code,  kp.minimum, kp.maximum, kp.required, kp.nrc, kp.mrc, kp.position,
           coalesce( nullif(kp.group_name,''),p.internal_name), case when kp.required = true then greatest(1,kp.minimum) else 0 end,
              REPLACE(common.get_long_translation(p.translation_uuid, v_lang), E'\n', '<br>')
    FROM products.kit_product kp join products.product p on p.code = kp.product_code
    WHERE kp.kit_id = NEW.kit_id;

    -- Update the corresponding fields in quotes.quote_rows
    UPDATE quotes.quote_rows
    SET
        internal_name = v_kit.internal_name,
        nrc_row = v_kit.nrc,
        mrc_row = v_kit.mrc,
        bundle_prefix_row = v_kit.bundle_prefix
    WHERE id = NEW.id;

    -- recupero il custom value legal_notes del kit se presente
    select coalesce( cv.value->>v_lang, '') as legal_note
    from products.kit_custom_value cv join products.kit k on cv.kit_id = k.id
    where k.id = NEW.kit_id and  key_name = 'legal_notes' into v_legal_note;

    if v_legal_note <> '' then
        update quotes.quote
        set notes = notes || '<br>' || v_legal_note
        where id = NEW.quote_id;
    end if;


    RETURN NEW;
END;
$function$
